insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at)
select k.id,'en',p.en_text,'approved',1,now()
from payload p join public.localization_keys k on k.translation_key=p.translation_key
where nullif(trim(p.en_text),'') is not null
on conflict (key_id,language_code) do update set translated_text=excluded.translated_text,status='approved',approved_at=now(),updated_at=now();

