rvice is {service}, totaling {total}."},{"translation_key":"smartReportsSource.status.targetAchieved","module":"smart_reports.core","ar_text":"تم تحقيق الهدف","en_text":"Target Achieved"},{"translation_key":"smartReportsSource.status.targetNotAchieved","module":"smart_reports.core","ar_text":"لم يكتمل الهدف","en_text":"Target Not Achieved"},{"translation_key":"smartReportsSource.status.notSpecified","module":"smart_reports.core","ar_text":"غير محدد","en_text":"Not Specified"},{"translation_key":"smartReportsSource.calendar.months.january","module":"smart_reports.core","ar_text":"يناير","en_text":"January"},{"translation_key":"smartReportsSource.calendar.months.January","module":"smart_reports.core","ar_text":"يناير","en_text":"January"},{"translation_key":"smartReportsSource.calendar.months.february","module":"smart_reports.core","ar_text":"فبراير","en_text":"February"},{"translation_key":"smartReportsSource.calendar.months.February","module":"smart_reports.core","ar_text":"فبراير","en_text":"February"},{"translation_key":"smartReportsSource.calendar.months.march","module":"smart_reports.core","ar_text":"مارس","en_text":"March"},{"translation_key":"smartReportsSource.calendar.months.March","module":"smart_reports.core","ar_text":"مارس","en_text":"March"},{"translation_key":"smartReportsSource.calendar.months.april","module":"smart_reports.core","ar_text":"أبريل","en_text":"April"},{"translation_key":"smartReportsSource.calendar.months.April","module":"smart_reports.core","ar_text":"أبريل","en_text":"April"},{"translation_key":"smartReportsSource.calendar.months.may","module":"smart_reports.core","ar_text":"مايو","en_text":"May"},{"translation_key":"smartReportsSource.calendar.months.May","module":"smart_reports.core","ar_text":"مايو","en_text":"May"},{"translation_key":"smartReportsSource.calendar.months.june","module":"smart_reports.core","ar_text":"يونيو","en_text":"June"},{"translation_key":"smartReportsSource.calendar.months.June","module":"smart_reports.core","