insert into public.localization_queue(translation_key,source_language,source_text,target_language,suggested_text,module,status)
select p.translation_key,'ar',p.ar_text,'fil',null,p.module,'pending'
from payload p
where not exists (
  select 1 from public.localization_values v
  join public.localization_keys k on k.id=v.key_id
  where k.translation_key=p.translation_key and v.language_code='fil' and v.status='approved'
)
on conflict (source_text,source_language,target_language,module) do nothing;

commit;

select
 count(*) filter (where v.language_code='ar' and v.status='approved') as arabic_approved,
 count(*) filter (where v.language_code='en' and v.status='approved') as english_approved
from public.localization_values v
join public.localization_keys k on k.id=v.key_id
where k.module='smart_reports.core';
